{
    "code": "ct_pds",
    "description": "Table des points de services",
    "disabled": false,
    "name": "ct_pds",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "id_pds",
            "description": "Identifiant du point de service",
            "fieldType": "STRING"
        },
        {
            "code": "num_compteur",
            "description": "Numéro du compteur",
            "fieldType": "STRING"
        },
        {
            "code": "exploitation",
            "description": "Identifiant de l’exploitation",
            "fieldType": "STRING"
        },
        {
            "code": "branchement",
            "description": "Identifiant du branchement",
            "fieldType": "STRING"
        },
        {
            "code": "tableau",
            "description": "Identifiant du tableau",
            "fieldType": "STRING"
        },
        {
            "code": "adresse",
            "description": "Localisation du point de service",
            "fieldType": "STRING",
            "maxValue": 4000
        },
        {
            "code": "roues",
            "description": "Nombre de roues",
            "fieldType": "LONG"
        },
        {
            "code": "nb_fils",
            "description": "Nombre de fils",
            "fieldType": "LONG"
        },
       {
            "code": "coefficient_lecture",
            "description": "Coefficient de lecture",
            "fieldType": "DOUBLE"
        },
        {
            "code": "puissance_transformateur",
            "description": "Puissance du transformateur",
            "fieldType": "LONG"
        },
        {
            "code": "is_transfo_avant_branchement",
            "description": "Indication sur l’emplacement du transfo",
            "fieldType": "LIST",
            "listValues": {
                "AVANT": "AVANT",
                "APRES": "APRES"
            }
        },
        {
            "code": "transformateur_intensite",
            "description": "Transformateur d'intensité",
            "fieldType": "BOOLEAN"
        },
        {
            "code": "gamme",
            "description": "Gamme",
            "fieldType": "STRING"
        },
        {
            "code": "longueur_conducteur",
            "description": "Longueur du conducteur",
            "fieldType": "LONG"
        },
        {
            "code": "date_resiliation_contrat",
            "description": "Date de résiliation du dernier contrat",
            "fieldType": "DATE"
        },
        {
            "code": "type_raccordement",
            "description": "Type de raccordement",
            "fieldType": "STRING"
        },
        {
            "code": "coef_tan_phi",
            "description": "Coefficient Tan Phi",
            "fieldType": "BOOLEAN"
        },
        {
            "code": "prime_mensuel_raccordement",
            "description": "Prime mensuelle de raccordement",
            "fieldType": "LONG"
        },
        {
            "code": "prime_mensuel_transformation",
            "description": "Prime mensuelle de transformation",
            "fieldType": "LONG"
        },
        {
            "code": "classe_compteur",
            "description": "Classe compteur",
            "fieldType": "DOUBLE"
        },
        {
            "code": "debut_validite",
            "description": "Date de début de validité",
            "fieldType": "DATE"
        },
        {
            "code": "fin_validite",
            "description": "Date de fin de validité",
            "fieldType": "DATE"
        },
        {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING",
            "maxValue": 200
        },
        {
            "code": "statut_pds",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "ACTIF": "ACTIF",
                "INACTIF": "INACTIF"
            }
        }
    ],
    "action": []
}
